CODE_EXAMPLE:
// Clean test: one concept, clear BUILD-OPERATE-CHECK structure
@Test
public void savedPage_canBeReloadedWithSameContent() throws Exception {
    // BUILD
    Page original = new Page("clean content");
    original.save();

    // OPERATE
    Page reloaded = Page.load(original.getId());

    // CHECK
    assertEquals(original.getContent(), reloaded.getContent());
}

UNIT_TEST_EXAMPLE:
@Test
public void savedPage_hasMatchingId() throws Exception {
    Page page = new Page("body");
    page.save();
    Page loaded = Page.load(page.getId());
    assertEquals(page.getId(), loaded.getId());
}

@Test
public void savedPage_hasMatchingContent() throws Exception {
    Page page = new Page("body");
    page.save();
    Page loaded = Page.load(page.getId());
    assertEquals("body", loaded.getContent());
}
